#include <vector>
#include <iostream>

std::vector<int> scores;
scores.push_back(90);   // إضافة في النهاية
scores.push_back(85);
scores.emplace_back(95); // يبني العنصر في المكان مباشرة (أكفأ للأنواع المعقدة)

// الوصول العشوائي بـ operator[] — لا يتحقق من الحدود
std::cout << scores[0]; // 90

// at() يتحقق من الحدود ويرمي out_of_range عند تجاوزها
std::cout << scores.at(1); // 85

// size() يُرجع عدد العناصر الحالي (من نوع size_t)
std::cout << "Count: " << scores.size(); // 3

#include <vector>

// قراءة عدد العناصر من مكان ما
const size_t count = 10000;

std::vector<float> vertices;
vertices.reserve(count);  // تخصيص الذاكرة مرة واحدة بدون تهيئة العناصر

for (size_t i = 0; i < count; ++i) {
    vertices.emplace_back(static_cast<float>(i));
    // لا تحدث إعادة تخصيص هنا لأن السعة كافية
}

// size() = عدد العناصر الفعلي
// capacity() = المساحة المحجوزة فعليًا
// بعد reserve: capacity >= count, size = 0 حتى نبدأ الإضافة
std::cout << "size: " << vertices.size();       // 10000
std::cout << "capacity: " << vertices.capacity(); // 10000 أو أكثر

