#include <deque>
#include <iostream>

std::deque<int> dq;
dq.push_back(10);   // النهاية: {10}
dq.push_back(20);   // النهاية: {10, 20}
dq.push_front(5);   // البداية: {5, 10, 20}
dq.push_front(1);   // البداية: {1, 5, 10, 20}

// الوصول العشوائي مثل vector
std::cout << dq[0];  // 1
std::cout << dq.at(2); // 10 (آمن: يتحقق من الحدود)

// front و back للوصول السريع للطرفين
std::cout << dq.front(); // 1
std::cout << dq.back();  // 20

#include <deque>
#include <iostream>

std::deque<int> dq = {10, 20, 30, 40, 50};

// pop_front و pop_back كلاهما O(1)
dq.pop_front(); // {20, 30, 40, 50}
dq.pop_back();  // {20, 30, 40}

// عكس deque بدون حاوية مؤقتة
std::deque<int> nums = {1, 2, 3, 4};
for (size_t i = 0; i < nums.size() / 2; ++i) {
    int front_val = nums.front();
    int back_val = nums.back();
    nums.front() = back_val;
    nums.back() = front_val;
    nums.pop_front();
    if (!nums.empty()) nums.pop_back();
}
// مع فرض حجم زوجي: nums تُعكَس

