#include <list>
#include <iostream>

int main() {
    std::list<int> lst = {10, 30, 50};
    auto it = lst.begin();
    ++it; // يشير لـ 30
    lst.insert(it, 20); // {10, 20, 30, 50}
    lst.erase(it);       // {10, 20, 50}
    for (int x : lst) std::cout << x << ' '; // 10 20 50
}

