#include <list>
#include <vector>

// ✅ vector: وصول عشوائي + إدراج في النهاية
std::vector<int> v = {1, 2, 3};
v.push_back(4);  // سريع
// v[1] = 20;     // سريع O(1)

// ✅ list: إدراج/حذف في المنتصف
std::list<int> lst = {1, 2, 3};
lst.push_back(4); // سريع
// لا يوجد lst[1]! يجب استخدام المكررات
