lst.insert(it, 20); // سريع O(1) — في vector يكون O(n)

#include <forward_list>
#include <iostream>

std::forward_list<int> nums = {10, 30, 40};

// insert_after: يُدرج بعد المكرر — لا يُدرج قبله
auto it = nums.begin(); // يشير لـ 10
nums.insert_after(it, 20); // {10, 20, 30, 40}

// erase_after: يحذف العنصر بعد المكرر
nums.erase_after(it); // يحذف 20 → {10, 30, 40}

// المرور للأمام فقط
for (int x : nums) {
    std::cout << x << ' '; // 10 30 40
}

#include <forward_list>
#include <iostream>

std::forward_list<std::string> tasks = {"render", "physics", "audio"};

// لا يوجد find() مدمج — استخدم std::find أو before_begin()
auto it = std::find(tasks.begin(), tasks.end(), "physics");
if (it != tasks.end()) {
    tasks.insert_after(it, "input");
}
// {"render", "physics", "input", "audio"}

// before_begin(): مكرر خاص قبل العنصر الأول
// مفيد لإدراج في المقدمة بدون push_front
auto pos = tasks.before_begin();
tasks.insert_after(pos, "init");
// {"init", "render", "physics", "input", "audio"}

// push_front أبسط لكن insert_after(before_begin()) مفيد في دوال عامة
for (const auto& t : tasks) {
    std::cout << t << ' ';
}

