// ولا تحتاج size() ولا المرور للخلف
// مثال: قائمة مهام تُضاف للمقدمة وتُعالج من المقدمة
std::forward_list<int> lifo;
lifo.push_front(1);
lifo.push_front(2);
lifo.pop_front(); // يُزيل 2

// ❌ لا تستخدمها لو تحتاج:
// - الوصول العشوائي → vector
// - push_back → vector أو deque أو list
// - size() → vector أو list (forward_list لا تملكها!)
// - المرور للخلف → list

// ⚠️ ملاحظة: size() غير موجودة في forward_list
// std::distance(begin, end) يعطي الحجم لكنها O(n)
