#include <map>
#include <iostream>

std::map<std::string, int> scores;
scores.insert({"Ali", 90});
scores.insert({"Sara", 95});
scores.insert({"Omar", 88});

// المرور دائمًا بالترتيب التصاعدي حسب المفتاح
for (const auto& [name, score] : scores) {
    std::cout << name << ": " << score << '\n';
}
// المخرج مرتب أبجديًا: Ali, Omar, Sara

#include <map>

std::map<int, std::string> events;
events[10] = "بدء التحميل";
events[20] = "اكتمل التحميل";
events[30] = "بدء المعالجة";
events[40] = "اكتملت المعالجة";

// lower_bound: أول عنصر بمفتاح >= 20
auto low = events.lower_bound(20);
// upper_bound: أول عنصر بمفتاح > 20
auto high = events.upper_bound(20);

// النطاق [low, high) يحتوي العناصر بمفتاح 20 فقط
for (auto it = low; it != high; ++it) {
    std::cout << it->second << '\n'; // "اكتمل التحميل"
}

// استخدام عملي: كل الأحداث بين 15 و35
for (auto it = events.lower_bound(15); it != events.upper_bound(35); ++it) {
    std::cout << it->first << ": " << it->second << '\n';
}

#include <map>

std::map<std::string, int> config;

// ❌ خطأ: operator[] يُنشئ عنصرًا بقيمة 0 إذا لم يكن موجودًا
