}

#include <set>
#include <string>
#include <iostream>

std::set<std::string> keywords;

// insert يُرجع زوجًا (مكرر، bool) — bool يُخبرك إن كان أُضيف فعلًا
auto [it, ok] = keywords.insert("render");
std::cout << ok; // true

auto [it2, ok2] = keywords.insert("render");
std::cout << ok2; // false — موجود مسبقًا

// find: O(log n) — أسرع من البحث الخطي
if (keywords.find("render") != keywords.end()) {
    std::cout << "موجود";
}

// contains (C++20) — أنظف
if (keywords.contains("update")) { /* ... */ }

// المرور دائمًا بالترتيب التصاعدي
for (const auto& kw : keywords) {
    std::cout << kw << '\n';
}

#include <set>

std::set<int> nums = {10, 20, 30, 40, 50};

// erase بالقيمة — يُرجع عدد العناصر المحذوفة (0 أو 1 في set)
size_t removed = nums.erase(30); // removed = 1

// erase بالمكرر — أسرع لأنه لا يبحث
auto it = nums.find(20);
if (it != nums.end()) {
    nums.erase(it); // لا يعيد مكرر في set (عكس vector)
}

// count دائمًا 0 أو 1 في set (مفيد كـ bool)
if (nums.count(40)) { /* موجود */ }

// lower_bound: أول عنصر >= 25
auto lb = nums.lower_bound(25);
// lb يشير لـ 40

