#include <map>
#include <iostream>

std::multimap<std::string, int> grades;

// insert يسمح بتكرار المفتاح بحرية
grades.insert({"Ali", 90});
grades.insert({"Ali", 85});
grades.insert({"Sara", 95});
grades.insert({"Ali", 88});

// count: عدد القيم لهذا المفتاح
std::cout << grades.count("Ali"); // 3

// النطاق [lower_bound, upper_bound) يحتوي كل قيم المفتاح
auto range = grades.equal_range("Ali");
for (auto it = range.first; it != range.second; ++it) {
    std::cout << it->second << ' '; // 90 85 88
}

// find يُرجع أول عنصر بالمفتاح فقط
auto it = grades.find("Ali");
std::cout << it->second; // 90 (الأول فقط)

#include <map>
#include <iostream>

std::multimap<int, std::string> log;
log.insert({1, "بدء"});
log.insert({1, "تحميل"});
log.insert({2, "معالجة"});
log.insert({2, "تحقق"});
log.insert({3, "انتهاء"});

// جميع الأحداث بالمستوى 2
for (auto it = log.lower_bound(2); it != log.upper_bound(2); ++it) {
    std::cout << it->second << ' '; // معالجة تحقق
}

// ❌ لا تستخدم find لو تريد الكل
auto f = log.find(2);
// f يشير للأول فقط — الباقي مخفي

// ✅ equal_range أنظف للمرور على الكل
auto [lo, hi] = log.equal_range(2);
for (auto it = lo; it != hi; ++it) {
    std::cout << it->second << '\n';
}

#include <map>
#include <unordered_map>

// ✅ multimap: تحتاج ترتيب + مفاتيح مكررة
// مثال: أحداث مرتبة زمنيًا بنفس الأولوية
std::multimap<int, std::string> timeline;
timeline.insert({5, "render"});
timeline.insert({5, "physics"}); // نفس الأولوية
// المرور يُعطيهم بالترتيب التصاعدي

// ✅ unordered_multimap: لا تحتاج ترتيب — أسرع
std::unordered_multimap<std::string, int> index;
index.insert({"shader", 1});
index.insert({"shader", 2}); // بحث O(1) بدل O(log n)

// ❌ map: لا تسمح بتكرار المفتاح
// std::map<int, std::string> m;
// m.insert({5, "a"});
// m.insert({5, "b"}); // الثانية مُتجاهلة!

// بديل شائع: map<string, vector<int>> بدل multimap
// لكنه أقل كفاءة عند الإدراج المتكرر
// لأنه يحتاج البحث ثم push_back في vector

#include <set>
#include <iostream>

std::multiset<int> temps = {22, 25, 22, 20, 25, 22};

// العناصر مرتبة تلقائيًا مع السماح بالتكرار
for (int t : temps) {
    std::cout << t << ' '; // 20 22 22 22 25 25
}

// count: كم مرة ظهرت القيمة
std::cout << temps.count(22); // 3

// equal_range: نطاق كل العناصر بالقيمة المحددة
auto [lo, hi] = temps.equal_range(22);
for (auto it = lo; it != hi; ++it) {
