#include <stack>
#include <string>
#include <iostream>

bool is_balanced(const std::string& expr) {
    std::stack<char> s;
    for (char c : expr) {
        if (c == '(' || c == '[' || c == '{') {
            s.push(c); // اقفل القوس المفتوح
        } else if (c == ')' || c == ']' || c == '}') {
            if (s.empty()) return false; // قوس إغلاق بدون فتح
            char open = s.top();
            s.pop();
            // تحقق من التطابق
            if (c == ')' && open != '(') return false;
            if (c == ']' && open != '[') return false;
            if (c == '}' && open != '{') return false;
        }
    }
    return s.empty(); // صحيح فقط إذا أُغلقت كل الأقواس
}

std::cout << is_balanced("(a + [b * {c}])"); // true
std::cout << is_balanced("(a + b");          // false

#include <stack>
#include <string>
#include <iostream>

std::string reverse_string(std::string s) {
    std::stack<char> st;
    for (char c : s) st.push(c);
    std::string result;
    result.reserve(s.size());
    while (!st.empty()) {
        result += st.top(); // آخر عنصر مُدخل = أول من يُقرأ
        st.pop();
    }
    return result;
}

std::cout << reverse_string("hello"); // olleh

