#include <queue>
#include <vector>
#include <functional>

// المعامل الثالث std::greater<int> يعكس الكومة فتصبح min-heap
// الحاوية الداخلية std::vector<int> مطلوبة عند تغيير المقارنة
std::priority_queue<int, std::vector<int>, std::greater<int>> min_pq;

// ندفع عناصر من قائمتين مرتبتين مفترضتين
min_pq.push(5); min_pq.push(1); min_pq.push(8);  // القائمة الأولى
min_pq.push(3); min_pq.push(4);                   // القائمة الثانية

std::vector<int> merged;
while (!min_pq.empty()) {
    merged.push_back(min_pq.top());  // top() يُرجع الأصغر في min-heap
    min_pq.pop();                     // pop() يُزيل الأصغر
}
// merged = {1, 3, 4, 5, 8}

#include <queue>
#include <vector>
#include <climits>

struct Edge { int node; int weight; };

// lambda يعكس الترتيب: الأصغر وزنًا = أعلى أولوية
auto cmp = [](const Edge& a, const Edge& b) { return a.weight > b.weight; };

// decltype(cmp) يستنتج نوع Lambda وcmp يُمرَّر للمُنشئ
std::priority_queue<Edge, std::vector<Edge>, decltype(cmp)> dijkstra(cmp);

dijkstra.push({0, 0}); // العقدة 0 بمسافة 0
std::vector<int> dist(5, INT_MAX);
dist[0] = 0;

while (!dijkstra.empty()) {
    auto [u, d] = dijkstra.top();
    dijkstra.pop();
    if (d > dist[u]) continue;  // تخطي النسخ القديمة غير المُحدَّثة
    // افتراض: graph[u] يحتوي أزواج {جار، وزن}
    for (auto [v, w] : graph[u]) {
        if (dist[u] + w < dist[v]) {
            dist[v] = dist[u] + w;
            dijkstra.push({v, dist[v]});  // دفع بمسافة جديدة (نسخة أحدث)
        }
    }
}

