#include <memory>
#include <iostream>

std::weak_ptr<int> observer;

void check() {
    // lock() يُرجع shared_ptr إذا الكائن حي، أو nullptr إذا دُمّر
    if (auto ptr = observer.lock()) {
        std::cout << "alive: " << *ptr << '\n';
    } else {
        std::cout << "destroyed\n";
    }
}

int main() {
    {
        auto sp = std::make_shared<int>(42);
        observer = sp;
        check(); // alive: 42
    } // sp تُدمَّر هنا
    check(); // destroyed

    // ⚠️ لا تستخدم observer مباشرة — لا يملك * أو ->
