class TextureCache {
    std::unordered_map<std::string, int> cache_;
    mutable std::shared_mutex mutex_;

public:
    // القراءة: قفل مشترك — عدة خيوط تقرأ معًا
    std::optional<int> get(const std::string& name) const {
        std::shared_lock<std::shared_mutex> lock(mutex_);
        auto it = cache_.find(name);
        if (it != cache_.end()) return it->second;
        return std::nullopt;
    }

    // الكتابة: قفل حصري — خيط واحد فقط
    void put(const std::string& name, int texture_id) {
        std::unique_lock<std::shared_mutex> lock(mutex_);
        cache_[name] = texture_id;
    }

    // التحقق من الوجود: قراءة فقط — قفل مشترك
    bool contains(const std::string& name) const {
        std::shared_lock<std::shared_mutex> lock(mutex_);
        return cache_.count(name) > 0;
    }
};

