void wait_with_timeout() {
    std::unique_lock<std::mutex> lock(mtx);

    // wait_for: ينتظر حتى 500ms أو حتى يتحقق الشرط
    bool success = cv.wait_for(lock, std::chrono::milliseconds(500),
        [&] { return data_ready; }
    );

    if (success) {
        std::cout << "البيانات جاهزة\n";
    } else {
        std::cout << "انتهت المهلة — لم تصل بيانات\n";
    }
}

void producer_delayed() {
    std::this_thread::sleep_for(std::chrono::milliseconds(200));
    {
        std::lock_guard<std::mutex> lock(mtx);
        data_ready = true;
    }
    cv.notify_one(); // يُوقظ قبل انتهاء المهلة
}

